import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "How do you calculate conception date?", a: "Conception is commonly estimated around ovulation, about 14 days before the next period or about 266 days before the due date." },
  { q: "Can you calculate conception date from due date?", a: "Yes. Subtract about 266 days from the estimated due date to estimate likely conception." },
  { q: "How accurate is a conception date calculator?", a: "It is an estimate because ovulation timing, implantation, ultrasound dating, and cycle variation can shift dates." },
  { q: "What is the difference between conception date and gestational age?", a: "Gestational age is counted from the last menstrual period, usually about two weeks before conception." },
  { q: "How long after conception can you test for pregnancy?", a: "Many tests can detect pregnancy around the time of a missed period, roughly two weeks after ovulation." },
];

const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
const fmt = (d: Date) => d.toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" });
const add = (d: Date, days: number) => { const next = new Date(d); next.setDate(next.getDate() + days); return next; };

export default function ConceptionCalculator() {
  const [mode, setMode] = useState<"due" | "lmp">("due");
  const [due, setDue] = useState("2027-02-05");
  const [lmp, setLmp] = useState("2026-05-01");
  const [cycle, setCycle] = useState(28);
  const result = useMemo(() => {
    if (mode === "due") { const dueDate = new Date(`${due}T00:00:00`); const conception = add(dueDate, -266); return { conception, ovulation: conception, fertileStart: add(conception, -5), fertileEnd: add(conception, 1), dueDate }; }
    const start = new Date(`${lmp}T00:00:00`); const ov = add(start, cycle - 14); return { conception: ov, ovulation: ov, fertileStart: add(ov, -5), fertileEnd: add(ov, 1), dueDate: add(start, 280) };
  }, [mode, due, lmp, cycle]);
  const timeline = [[0, 2, "First", "Likely conception", result.conception], [4, 6, "First", "Early positive test window", add(result.conception, 28)], [8, 10, "First", "Major organs developing", add(result.conception, 56)], [12, 14, "First", "End of first trimester approaches", add(result.conception, 84)], [20, 22, "Second", "Anatomy scan period", add(result.conception, 140)], [28, 30, "Third", "Third trimester begins", add(result.conception, 196)], [36, 38, "Third", "Late pregnancy", add(result.conception, 252)], [38, 40, "Third", "Estimated due date period", result.dueDate]];
  return (
    <>
      <SEOHead title="Free Conception Calculator Online - Calculate Likely Conception Date Instantly | CalcHive" description="Free online conception calculator. Calculate your likely conception date from your due date or find your conception window from your last menstrual period instantly. 100% free, no signup required." canonical="/conception-calculator" keywords="free conception calculator, when did I conceive calculator free online, conception date calculator free, calculate conception date from due date free, pregnancy conception window calculator free" category="Health Calculators" breadcrumbName="Free Conception Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Conception Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Estimate likely conception date from due date or last period and cycle length.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold block mb-2">Mode</label><select value={mode} onChange={(e) => setMode(e.target.value as "due" | "lmp")} className={inputClass}><option value="due">Calculate from due date</option><option value="lmp">Calculate from last period</option></select></div>{mode === "due" ? <div><label className="text-sm font-semibold block mb-2">Due date</label><input type="date" value={due} onChange={(e) => setDue(e.target.value)} className={inputClass} /></div> : <><div><label className="text-sm font-semibold block mb-2">Last period start</label><input type="date" value={lmp} onChange={(e) => setLmp(e.target.value)} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Cycle length</label><input type="number" value={cycle} onChange={(e) => setCycle(Number(e.target.value))} className={inputClass} /></div></>}</div><div className="bg-gradient-to-br from-teal-500 to-teal-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Likely Conception Date</p><p className="text-4xl sm:text-5xl font-black text-white">{fmt(result.conception)}</p></div><div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Fertile start</p><p className="text-lg font-extrabold">{fmt(result.fertileStart)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Fertile end</p><p className="text-lg font-extrabold">{fmt(result.fertileEnd)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Due date</p><p className="text-lg font-extrabold">{fmt(result.dueDate)}</p></div></div></section><MedicalDisclaimer variant="pregnancy" /><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold">How to Calculate Your Conception Date for Free</h2><p className="text-muted-foreground leading-relaxed">Use due date minus about 266 days, or estimate ovulation from the last period and cycle length.</p><h2 className="text-2xl font-bold">How to Find When You Conceived From Your Due Date</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold mb-3">Pregnancy Timeline From Conception</caption><thead className="bg-muted/60"><tr>{["Week From Conception", "Gestational Week", "Trimester", "Key Development", "Approximate Date"].map((h) => <th key={h} className="text-left py-3 px-3">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{timeline.map((r) => <tr key={String(r[0])}>{r.map((c, i) => <td key={`${r[0]}-${i}`} className="py-2.5 px-3">{c instanceof Date ? fmt(c) : c}</td>)}</tr>)}</tbody></table></div><h2 className="text-2xl font-bold">Free Pregnancy Conception Date Tool for Everyone</h2></section>
        <section className="mb-8"><h3 className="text-xl font-bold mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/conception-calculator" headingLevel="h3" /></main>
    </>
  );
}


